// build-theme-rules — Validate Inputs
// Checks required artifacts and passes all upstream data through.

const input = $input.first().json;

const storeProfile     = input.store_profile     || null;
const brandPositioning = input.brand_positioning || null;
const projectId        = input.project_id        || (input.runtime_config && input.runtime_config.project_id) || null;

if (!projectId) {
  throw new Error('MISSING_INPUT: build-theme-rules requires project_id');
}
if (!storeProfile) {
  throw new Error('MISSING_ARTIFACT: store_profile is required for store pattern classification');
}
if (!brandPositioning) {
  throw new Error('MISSING_ARTIFACT: brand_positioning is required for store pattern classification');
}

// Optional upstream artifacts — all gracefully defaulted
const marketIntelligence = input.market_intelligence  || {};
const competitorClusters = input.competitor_clusters  || {};
const strategySynthesis  = input.strategy_synthesis   || {};
const offerArchitecture  = input.offer_architecture   || {};
const contentStrategy    = input.content_strategy     || {};
const storeBlueprint     = input.store_blueprint      || {};
const runtimeConfig      = input.runtime_config       || {};

return [{
  json: {
    project_id:          projectId,
    runtime_config:      runtimeConfig,
    store_profile:       storeProfile,
    brand_positioning:   brandPositioning,
    market_intelligence: marketIntelligence,
    competitor_clusters: competitorClusters,
    strategy_synthesis:  strategySynthesis,
    offer_architecture:  offerArchitecture,
    content_strategy:    contentStrategy,
    store_blueprint:     storeBlueprint,
  },
}];

// build-theme-rules — Classify Store Pattern (Phase 10B)
// Pure function: upstream artifact fields → one of 7 store patterns.
// Priority-ordered classification. First match wins.
//
// Patterns:
//   technical-b2b-specialist  — specialist + technical-trustworthy tone
//   premium-minimalist        — luxury/premium price + premium/editorial tone
//   lifestyle-emotional-dr    — high emotional intensity or warm-helpful tone
//   value-led-general         — budget/mass-market price or value-leader role
//   catalog-first-specialist  — broad catalog + category-specialist store type
//   editorial-curator         — editorial-guide role or editorial-smart tone
//   single-product-focused    — single-product catalog or single-hero assortment

const input = $input.first().json;
const sp = input.store_profile;
const bp = input.brand_positioning;

const toneStyle          = (bp.tone_of_voice && bp.tone_of_voice.style)              || 'clear-direct';
const emotionalIntensity = (bp.tone_of_voice && bp.tone_of_voice.emotional_intensity) || 'medium';
const brandRole          = bp.brand_role       || 'specialist';
const pricePositioning   = sp.price_positioning || 'mass-market';
const catalogType        = sp.catalog_type      || 'small-curated-catalog';
const assortmentShape    = sp.assortment_shape  || 'unknown';
const storeType          = sp.store_type        || 'multi-product-store';

let pattern  = null;
let rationale = null;

// ── Priority 1: Single product — always wins ────────────────────────────
if (catalogType === 'single-product' || assortmentShape === 'single-hero-product') {
  pattern   = 'single-product-focused';
  rationale = 'catalog_type=' + catalogType + ' / assortment_shape=' + assortmentShape + ' → single-product homepage: full hero, benefit stack, guarantee, cross-sell';
}

// ── Priority 2: Luxury/premium + premium/editorial tone ────────────────
else if (['luxury', 'premium'].includes(pricePositioning) && ['premium-confident', 'editorial-smart'].includes(toneStyle)) {
  pattern   = 'premium-minimalist';
  rationale = 'price_positioning=' + pricePositioning + ' + tone=' + toneStyle + ' → premium minimalist: generous whitespace, curated 2-col grid, subtle CTAs';
}

// ── Priority 3: Editorial guide role or editorial-smart tone ───────────
else if (brandRole === 'editorial-guide' || toneStyle === 'editorial-smart') {
  pattern   = 'editorial-curator';
  rationale = 'brand_role=' + brandRole + ' / tone=' + toneStyle + ' → editorial structure: content-first, 2-col grid, minimal trust signals';
}

// ── Priority 4: Specialist + technical-trustworthy → B2B specialist ────
else if (brandRole === 'specialist' && toneStyle === 'technical-trustworthy') {
  pattern   = 'technical-b2b-specialist';
  rationale = 'brand_role=specialist + tone=technical-trustworthy → B2B: hero → value-prop → collection → evidence trust';
}

// ── Priority 5: Budget/mass-market or value-leader ─────────────────────
else if (['budget', 'mass-market'].includes(pricePositioning) || brandRole === 'value-leader') {
  pattern   = 'value-led-general';
  rationale = 'price_positioning=' + pricePositioning + ' / brand_role=' + brandRole + ' → value-led: density-focused, assertive CTAs, guarantee trust';
}

// ── Priority 6: Broad catalog + category specialist ─────────────────────
else if (['broad-catalog', 'mixed-catalog'].includes(catalogType) && storeType === 'category-specialist') {
  pattern   = 'catalog-first-specialist';
  rationale = 'catalog_type=' + catalogType + ' + store_type=category-specialist → catalog-first: compact hero, 4-col grid, filter prominence';
}

// ── Priority 7: High emotional intensity or warm tone ──────────────────
else if (emotionalIntensity === 'high' || toneStyle === 'warm-helpful') {
  pattern   = 'lifestyle-emotional-dr';
  rationale = 'emotional_intensity=' + emotionalIntensity + ' / tone=' + toneStyle + ' → lifestyle DR: emotional hero → social proof → 4-col grid → benefits';
}

// ── Default fallback ────────────────────────────────────────────────────
else {
  pattern   = 'technical-b2b-specialist';
  rationale = 'Default fallback (no priority rule matched). Inputs: brand_role=' + brandRole + ', tone=' + toneStyle + ', price=' + pricePositioning + ', catalog=' + catalogType;
}

return [{
  json: {
    ...input,
    store_pattern:     pattern,
    pattern_rationale: rationale,
    _classification_inputs: {
      brand_role:          brandRole,
      tone_style:          toneStyle,
      emotional_intensity: emotionalIntensity,
      price_positioning:   pricePositioning,
      catalog_type:        catalogType,
      assortment_shape:    assortmentShape,
      store_type:          storeType,
    },
  },
}];

