    },
    trust_model:         { primary_proof: 'guarantee',       prominence: 'medium', placement: 'end-of-page' },
    conversion_model:    { cta_style: 'assertive',  urgency_level: 'high',   bundle_promo: true },
    merchandising_model: { primary_pattern: 'product-grid',          grid_columns: 4, collection_prominence: 'primary' },
    visual_system:       { density: 'high',   whitespace: 'tight',     contrast: 'punchy-commercial' },
    page_template_rules: { product_page: 'standard',    collection_page: 'grid-dense',        about_page: 'minimal' },
