const rules = PATTERN_RULES[pattern] || PATTERN_RULES['technical-b2b-specialist'];

return [{
  json: {
    ...input,
    homepage_layout:      rules.homepage_layout,
    section_system:       rules.section_system,
    trust_model:          rules.trust_model,
    conversion_model:     rules.conversion_model,
    merchandising_model:  rules.merchandising_model,
    visual_system_rules:  rules.visual_system,
    page_template_rules:  rules.page_template_rules,
    media_placement_rules:rules.media_placement_rules,
  },
