// build-theme-rules — Enrich Rules with Content Strategy (Phase 10F)
// Applies content_strategy messaging and store_blueprint hints to section stack.
// Primary message → hero heading. Brand traits → value-prop content hint.
// Blueprint section content overrides (heading_hint, cta_label, cta_target) propagated.

const input = $input.first().json;
const cs        = input.content_strategy  || {};
const blueprint = input.store_blueprint   || {};
const bp        = input.brand_positioning || {};
const sectionStack = input.homepage_layout.section_stack;

// Build blueprint lookup by section_type for fallback hints
const blueprintByType = {};
for (const s of (blueprint.theme_sections || [])) {
  const key = (s.section_type || '').toLowerCase();
  blueprintByType[key] = s;
}

// Primary message from content_strategy
const primaryMessage = (cs.messaging_hierarchy && cs.messaging_hierarchy.primary_message) || null;

// Brand traits for value-prop hint
const brandTraits = (bp.brand_traits && bp.brand_traits.length > 0)
  ? bp.brand_traits.slice(0, 4).join(', ')
  : null;

// Trust style hint for trust section
const trustProofMode = (bp.trust_style && bp.trust_style.proof_mode) || 'evidence-led';
const trustHint = 'Trust signals: ' + trustProofMode.replace(/-/g, ' ');

// Enrich each section in stack
const enrichedStack = sectionStack.map(section => {
  const bpSection = blueprintByType[section.section_type] || {};

  // Start with rule defaults, then overlay blueprint hints, then apply strategy-derived hints
  let heading_hint = section.heading_hint || bpSection.heading_hint || null;
  let content_hint = section.content_hint || bpSection.content_hint || null;
  let cta_label    = section.cta_label    || bpSection.cta_label    || null;
  let cta_target   = section.cta_target   || bpSection.cta_target   || null;

  if (section.section_type === 'hero') {
    // Primary message from content_strategy overrides blueprint heading
    if (primaryMessage && !heading_hint) {
      heading_hint = primaryMessage;
    }
    // Default CTA for hero
    if (!cta_label) cta_label = 'Shop Now';
    if (!cta_target) cta_target = '/collections/all';
  }

  if (section.section_type === 'value-prop') {
    if (!content_hint && brandTraits) {
      content_hint = 'Key values: ' + brandTraits;
    }
    if (!heading_hint) {
      heading_hint = 'Why Choose Us';
    }
  }

  if (section.section_type === 'trust-social-proof') {
    if (!content_hint) {
      content_hint = trustHint;
    }
    if (!heading_hint) {
      heading_hint = 'Trusted by Customers';
    }
  }

  if (section.section_type === 'featured-collection') {
    if (!heading_hint) {
      heading_hint = 'Featured Products';
    }
    if (!cta_label) cta_label = 'View All';
    if (!cta_target) cta_target = '/collections/all';
  }

  return {
    ...section,
    heading_hint,
    content_hint,
    cta_label,
    cta_target,
  };
});

return [{
  json: {
    ...input,
    homepage_layout: {
      ...input.homepage_layout,
      section_stack: enrichedStack,
    },
  },
}];

// build-theme-rules — Compile Theme Rules Artifact
// Assembles the final theme_rules artifact with status, timestamps, and derived_from provenance.
// Also passes through all upstream artifacts so the orchestrator chain can continue.

const input = $input.first().json;
const sp = input.store_profile     || {};
const bp = input.brand_positioning || {};
const cs = input.content_strategy  || {};

const themeRules = {
  status:             'PHASE_10_COMPLETE',
  project_id:         input.project_id,
  completed_at:       new Date().toISOString(),
  store_pattern:      input.store_pattern,
  pattern_rationale:  input.pattern_rationale,
  homepage_layout:    input.homepage_layout,
  section_system:     input.section_system,
  trust_model:        input.trust_model,
  conversion_model:   input.conversion_model,
  merchandising_model:input.merchandising_model,
  visual_system:      input.visual_system_rules,
  page_template_rules:  input.page_template_rules,
  media_placement_rules:input.media_placement_rules,
  derived_from: {
    brand_role:        bp.brand_role         || null,
    tone_of_voice:     (bp.tone_of_voice && bp.tone_of_voice.style) || null,
    price_positioning: sp.price_positioning  || null,
    store_type:        sp.store_type         || null,
    catalog_type:      sp.catalog_type       || null,
    trust_style:       (bp.trust_style && bp.trust_style.proof_mode) || null,
    conversion_style:  (bp.conversion_style && bp.conversion_style.cta_style) || null,
    primary_message:   (cs.messaging_hierarchy && cs.messaging_hierarchy.primary_message) || null,
  },
};

console.log('build-theme-rules: pattern=' + themeRules.store_pattern + ' sections=' + themeRules.homepage_layout.section_stack.filter(s => s.enabled).length + ' enabled');

// Return theme_rules embedded in the full artifact passthrough
// Orchestrator reads theme_rules from this output and passes to build-shopify-theme
return [{
  json: {
    project_id:          input.project_id,
    runtime_config:      input.runtime_config,
    store_profile:       input.store_profile,
    brand_positioning:   input.brand_positioning,
    market_intelligence: input.market_intelligence,
    competitor_clusters: input.competitor_clusters,
    strategy_synthesis:  input.strategy_synthesis,
    offer_architecture:  input.offer_architecture,
    content_strategy:    input.content_strategy,
    store_blueprint:     input.store_blueprint,
    theme_rules:         themeRules,
  },
}];
